+fn render_markdown_table(
+    headers: &[PlainCell],
+    rows: &[Vec<PlainCell>],
+    widths: &[usize],
+) -> String {
+    let mut output = String::new();
+    push_pipe_row(&mut output, headers, widths);
+    output.push('\n');
+    push_markdown_separator(&mut output, headers, widths);
+
+    for row in rows {
+        output.push('\n');
+        push_pipe_row(&mut output, row, widths);
+    }
+
